#include <omp.h>
#include <math.h> // For exp

// Define structures and constants from main.h and other headers if not included by the target main.c
#ifndef FP_TYPE
#define FP_TYPE double
#endif

#ifndef NUMBER_PAR_PER_BOX
#define NUMBER_PAR_PER_BOX 100
#endif

#ifndef NUMBER_THREADS
#define NUMBER_THREADS 128
#endif

#ifndef DOT
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))
#endif

typedef struct {
    FP_TYPE x, y, z;
} THREE_VECTOR;

typedef struct {
    FP_TYPE v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    FP_TYPE alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

// Function prototype for the kernel
void kernel_cpu(par_str par_cpu, dim_str dim_cpu, box_str* box_cpu, FOUR_VECTOR* rv_cpu, FP_TYPE* qv_cpu, FOUR_VECTOR* fv_cpu);

void kernel_cpu(par_str par_cpu,
                dim_str dim_cpu,
                box_str* box_cpu,
                FOUR_VECTOR* rv_cpu,
                FP_TYPE* qv_cpu,
                FOUR_VECTOR* fv_cpu)
{
    FP_TYPE a2 = 2.0 * par_cpu.alpha * par_cpu.alpha;

    #pragma omp parallel for schedule(static)
    for (int bx = 0; bx < dim_cpu.number_boxes; ++bx) {
        // Home box parameters
        int first_i = box_cpu[bx].offset;
        FOUR_VECTOR* rA = &rv_cpu[first_i];
        FOUR_VECTOR* fA = &fv_cpu[first_i];

        // Neighbor box loop
        for (int k = 0; k <= box_cpu[bx].nn; ++k) {
            int pointer;
            if (k == 0) {
                pointer = bx; // Home box
            } else {
                pointer = box_cpu[bx].nei[k - 1].number; // Neighbor box
            }

            // Neighbor box parameters
            int first_j = box_cpu[pointer].offset;
            FOUR_VECTOR* rB = &rv_cpu[first_j];
            FP_TYPE* qB = &qv_cpu[first_j];

            // Calculation loop for particles within the boxes
            #pragma omp for schedule(static) nowait
            for (int i = 0; i < NUMBER_PAR_PER_BOX; ++i) {
                for (int j = 0; j < NUMBER_PAR_PER_BOX; ++j) {
                    FP_TYPE r2;
                    FP_TYPE u2;
                    FP_TYPE vij;
                    FP_TYPE fs;
                    FP_TYPE fxij, fyij, fzij;
                    THREE_VECTOR d;

                    r2 = (FP_TYPE)rA[i].v + (FP_TYPE)rB[j].v - DOT((FP_TYPE)rA[i], (FP_TYPE)rB[j]);
                    u2 = a2 * r2;
                    vij = exp(-u2);
                    fs = 2 * vij;

                    d.x = (FP_TYPE)rA[i].x - (FP_TYPE)rB[j].x;
                    fxij = fs * d.x;
                    d.y = (FP_TYPE)rA[i].y - (FP_TYPE)rB[j].y;
                    fyij = fs * d.y;
                    d.z = (FP_TYPE)rA[i].z - (FP_TYPE)rB[j].z;
                    fzij = fs * d.z;

                    fA[i].v += (double)((FP_TYPE)qB[j] * vij);
                    fA[i].x += (double)((FP_TYPE)qB[j] * fxij);
                    fA[i].y += (double)((FP_TYPE)qB[j] * fyij);
                    fA[i].z += (double)((FP_TYPE)qB[j] * fzij);
                }
            }
        }
    }
}
